;; Story layer: cell specials (data, never evaluated — see src/specials.lisp).

;; :dark 3 — dark at all hours, but with three cells of sight (a torch
;; still buys the fourth); plain :dark t would clamp sight to one cell.
(zone :kind :dungeon :title "the cellar" :dark 3)

(special (0 0)
  (once (message "You descend into the cellar.  Rats squeal in the dark."
                 "Find the stairs down (>).")))

(special (1 2)
  (once (message "Something stirs in the darkness...")
        (encounter ("giant rat" "1d3+1"))))

(special (0 4)
  (once (message "A loose stone hides a small cache.")
        (gold "3d10")))

(special (5 4)
  (message "You climb the ladder back up to the tavern.")
  (travel "town.map" 6 2 :south))

(special (3 2)
  (message "Stone stairs spiral down into darkness.  Your tale continues...")
  (event :game-won))
